  "marker": "PR97135-RUNTIME-PROOF-2026-06-27T14:36:02.903Z",
  "head": "076f03256a30d164453efbade434e395e72e6383",
  "proofRoot": "/var/folders/r8/x37z43b52tv63kn_ss3571t40000gp/T/openclaw-pr97135-proof-QY2c1J",
  "scenarios": [
    {
      "verboseLevel": "on",
      "dispatchResult": {
        "queuedFinal": true,
        "counts": {
          "tool": 0,
          "block": 0,
          "final": 1
        }
      },
      "callbackCounts": {
